+interface SourceFingerprint {
+	exists: boolean;
+	size?: bigint;
+	mtimeNs?: bigint;
+}
+
+async function sourceFingerprints(paths: readonly string[]): Promise<SourceFingerprint[]> {
+	return Promise.all(paths.map((path) => sourceFingerprint(path)));
